     }
   }
   ```

2. **If you want to use hooks (recommended for new code):**
   ```jsx
   import React, { useEffect } from 'react';

   function MyComponent() {
     useEffect(() => {
       // This runs on mount and on updates
       console.log('Component mounted or updated');

       return () => {
         // This runs on unmount
         console.log('Component will unmount');
       };
     }, []); // Empty dependency array means it only runs on mount/unmount

     return <div>My Component</div>;
   }
   ```

3. **If you're getting this error in a non-component file:**
   Make sure you're only using React hooks inside React function components. Move your hook usage into a proper component.

### Common Mistakes:
- Forgetting to import `useEffect` from 'react'
- Using hooks in class components
- Using hooks in regular JavaScript functions that aren't React components
- Using hooks inside loops, conditions, or nested functions

